#include<bits/stdc++.h>
using namespace std;
struct node{
    string x;
    int y;
}a[105];
vector<node> v;
bool cmp(node a,node b){
    return a.y>b.y;
}
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i].x>>a[i].y;
    for(int i=1;i<=n;i++) {if(a[i].y>=60){ v.push_back({a[i].x,a[i].y});a[i].x="-1";}}
    stable_sort(v.begin(),v.end(),cmp);
    for(int i=0;i<v.size();i++) cout<<v[i].x<<"\n";
     for(int i=1;i<=n;i++) if(a[i].x!="-1") cout<<a[i].x<<"\n";
    return 0;
}
